<?php
namespace Tests\Unit\Domain\Inventory;
use App\Domain\Equipment\Data\ItemStatBonuses;use App\Domain\Inventory\Instances\Refinement\ItemRefinementStatCalculator;use App\Models\RefinementStatModifier;use PHPUnit\Framework\TestCase;
class ItemRefinementStatCalculatorTest extends TestCase{private function raw($overrides=[]){return array_merge(['max_health'=>0,'attack'=>0,'defense'=>0,'accuracy'=>0,'evasion'=>0,'critical_chance'=>'0.00','attack_speed'=>'0.00'],$overrides);}private function modifier($level,$points,$status='active'){$m=new RefinementStatModifier();$m->refinement_level=$level;$m->stat_increase_basis_points=$points;$m->status=$status;return$m;}public function test_level_three_uses_only_its_accumulated_modifier(){ $r=(new ItemRefinementStatCalculator())->calculate($this->raw(['attack'=>10]),3,$this->modifier(3,3000));$this->assertSame(3,$r->refinement()->attack());$this->assertSame(13,$r->total()->attack());$this->assertSame(3000,$r->basisPoints());}public function test_decimal_scaling_is_exact(){ $this->assertSame(10,ItemStatBonuses::decimalToHundredths('0.10'));$this->assertSame(525,ItemStatBonuses::decimalToHundredths('5.25'));$r=(new ItemRefinementStatCalculator())->calculate($this->raw(['critical_chance'=>'5.25','attack_speed'=>'0.10']),3,$this->modifier(3,3000));$this->assertSame(1.57,$r->refinement()->criticalChance());$this->assertSame(0.03,$r->refinement()->attackSpeed());$this->assertSame(6.82,$r->total()->criticalChance());$this->assertSame(0.13,$r->total()->attackSpeed());}public function test_floor_zero_and_zero_base_are_preserved(){ $r=(new ItemRefinementStatCalculator())->calculate($this->raw(['attack'=>4,'defense'=>0]),1,$this->modifier(1,1000));$this->assertSame(0,$r->refinement()->attack());$this->assertSame(4,$r->total()->attack());$this->assertSame(0,$r->total()->defense());}public function test_zero_missing_and_inactive_policy(){ $calculator=new ItemRefinementStatCalculator();$zero=$calculator->calculate($this->raw(['attack'=>10]),0);$this->assertTrue($zero->configured());$this->assertSame(0,$zero->refinement()->attack());$missing=$calculator->calculate($this->raw(['attack'=>10]),4);$this->assertFalse($missing->configured());$this->assertNull($missing->basisPoints());$this->assertSame(0,$missing->refinement()->attack());}}
